path = Path('/ctf-workspace/heartbleed_msf.bin')
data = path.read_bytes()
def search(prefix):
    offsets = []
    for i in range(len(data)-2):
        if data[i] == 0x30 and data[i+1] == prefix:
            offsets.append(i)
    return offsets

for prefix in (0x80, 0x81, 0x82):
